framework_css:
/*
  Design system & layout for CNC milling machines manufacturer site
  Matches dark, industrial, minimal style from the provided design.
*/

/* ===== Font imports (optional, can be self-hosted) ===== */
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=IBM+Plex+Sans:wght@300;400;500;600&display=swap');

/* ===== CSS Variables ===== */
:root {
  /* Core palette */
  --color-primary-yellow: #FFC028;
  --color-primary-bg: #181A1B; /* header/footer charcoal */
  --color-page-bg: #101010;    /* main page background */

  --color-secondary-light: #F5F5F5;
  --color-secondary-muted: #B3B3B3;

  --color-accent-green: #00C853;

  --color-neutral-white: #FFFFFF;
  --color-neutral-border: #2A2A2A;
  --color-neutral-soft: #E0E0E0;
  --color-neutral-muted: #A0A0A0;

  --color-semantic-success: #00C853;
  --color-semantic-error: #E53935;
  --color-semantic-warning: #FFC107;
  --color-semantic-info: #29B6F6;

  /* Typography */
  --font-heading: 'Space Grotesk', 'Helvetica Neue', Helvetica, Arial, sans-serif;
  --font-body: 'IBM Plex Sans', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-code: 'Source Code Pro', Menlo, Monaco, Consolas, 'Courier New', monospace;

  --font-size-body: 16px;
  --font-size-small: 13px;
  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --header-height: 72px;
  --page-max-width: 1200px;
}

/* ===== Reset / Base ===== */
* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-secondary-light);
  background-color: var(--color-page-bg);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible,
button:focus-visible {
  outline: 2px solid var(--color-accent-green);
  outline-offset: 2px;
}

.page-shell {
  min-height: 100vh;
  background-color: var(--color-page-bg);
}

.container {
  max-width: var(--page-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-5);
  padding-right: var(--space-5);
}

/* ===== Header ===== */
.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background-color: var(--color-primary-bg);
}

.header-inner {
  height: var(--header-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.logo {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 20px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-primary-yellow);
  white-space: nowrap;
}

.logo-text {
  display: inline-block;
}

/* Primary navigation */
.primary-nav {
  flex: 1;
  margin-left: var(--space-5);
}

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;

  display: flex;
  justify-content: flex-end;
  align-items: center;
  column-gap: 40px;
}

.primary-nav-item {
  position: relative;
}

.primary-nav-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-secondary-light);
  padding-bottom: 4px;
  transition: color 160ms ease-out, border-color 160ms ease-out;
  border-bottom: 2px solid transparent;
}

.primary-nav-link:hover,
.primary-nav-link:active {
  color: var(--color-primary-yellow);
  border-bottom-color: var(--color-primary-yellow);
}

.primary-nav-link.is-active {
  color: var(--color-primary-yellow);
  border-bottom-color: var(--color-primary-yellow);
}

/* ===== Main content wrapper ===== */
.page-content {
  padding-top: var(--space-6);
  padding-bottom: var(--space-7);
  padding-left: var(--space-5);
  padding-right: var(--space-5);
}

/* Example of a centered hero frame if used by pages */
.page-content .hero-frame {
  max-width: var(--page-max-width);
  margin: 0 auto;
  border-radius: 4px;
  overflow: hidden;
}

/* ===== Footer ===== */
.site-footer {
  background-color: var(--color-primary-bg);
  color: var(--color-secondary-muted);
  border-top: 1px solid var(--color-neutral-border);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  padding-top: var(--space-6);
  padding-bottom: var(--space-4);
  column-gap: var(--space-6);
  row-gap: var(--space-5);
}

.footer-brand {
  flex: 1 1 260px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 18px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-primary-yellow);
  margin-bottom: var(--space-2);
}

.footer-tagline {
  margin: 0;
  max-width: 320px;
  font-size: 14px;
  line-height: var(--line-height-relaxed);
  color: var(--color-secondary-muted);
}

.footer-links-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: var(--space-4);
  flex: 2 1 480px;
}

.footer-column {
  min-width: 160px;
}

.footer-heading {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-size: 11px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-secondary-light);
}

.footer-links-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-link {
  display: inline-block;
  margin-bottom: var(--space-1);
  font-size: 14px;
  color: var(--color-secondary-muted);
  transition: color 160ms ease-out;
}

.footer-link:hover {
  color: var(--color-primary-yellow);
}

.footer-bottom {
  border-top: 1px solid var(--color-neutral-border);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
}

.footer-meta {
  margin: 0;
  font-size: 12px;
  color: var(--color-neutral-muted);
}

/* ===== Floating Cart Button (FAB) ===== */
.fab-cart {
  position: fixed;
  right: var(--space-4);
  bottom: var(--space-4);
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background-color: var(--color-neutral-white);
  box-shadow: 0 10px 24px rgba(0, 0, 0, 0.45);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  z-index: 90;
}

.fab-cart::before,
.fab-cart::after {
  content: '';
  display: block;
  background-color: var(--color-accent-green);
}

/* Simple keyhole-like shape built purely in CSS */
.fab-cart::before {
  width: 12px;
  height: 12px;
  border-radius: 50%;
}

.fab-cart::after {
  width: 6px;
  height: 12px;
  margin-top: -2px;
  border-radius: 0 0 6px 6px;
}

.fab-cart:hover {
  box-shadow: 0 14px 32px rgba(0, 0, 0, 0.6);
}

/* ===== Responsive adjustments ===== */
@media (max-width: 1024px) {
  .primary-nav-list {
    column-gap: 24px;
  }
}

@media (max-width: 880px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    padding-top: var(--space-3);
    padding-bottom: var(--space-3);
    height: auto;
  }

  .primary-nav {
    width: 100%;
    margin-left: 0;
    margin-top: var(--space-3);
  }

  .primary-nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-2);
    justify-content: flex-start;
  }

  .footer-links-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .container {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .page-content {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .footer-links-grid {
    grid-template-columns: 1fr;
  }

  .footer-bottom-inner {
    flex-direction: column;
    align-items: flex-start;
    row-gap: var(--space-2);
  }

  .fab-cart {
    right: var(--space-3);
    bottom: var(--space-3);
  }
}
